{
  "name": "IAN: The Legacy Fellowship",
  "description": "A dual-facing platform for retired Interpol officials. The Veranda serves as a public tribute, while The Vault provides a secure, AI-assisted private fellowship network.",
  "requestFramePermissions": []
}

import React, { useState, useEffect } from 'react';
import { ViewState, Member, AppEvent, ForumPost, ForumTopic, LanguageCode } from '../types';
import { MOCK_MEMBERS, FORUM_TOPICS, MOCK_EVENTS, MOCK_FORUM_POSTS, MEMBERSHIP_TIERS, INTERPOL_LANGUAGES } from '../constants';
import { Archie } from './Archie';
import { 
  Users, Calendar, FileText, Heart, Search, 
  LogOut, ShieldCheck, MapPin, MessageSquare, Globe,
  Youtube, ExternalLink, PlusCircle, ArrowLeft, Send, BadgeCheck, CreditCard, Award, CheckCircle2, X, Upload, FileCheck, Lock, Clock, Info, Navigation, Paperclip
} from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface VaultProps {
  currentView: ViewState;
  onNavigate: (view: ViewState) => void;
  onLogout: () => void;
  isNewUser?: boolean;
}

export const Vault: React.FC<VaultProps> = ({ currentView, onNavigate, onLogout, isNewUser = false }) => {
  const [activeTopic, setActiveTopic] = useState<ForumTopic & { startDocument?: string } | null>(null);
  const { t, language, setLanguage } = useLanguage();

  // Membership Check (Simplified for Mock)
  // Ross Halliday is "Founding Director" which maps to "Legacy Fellow" (Paid Tier)
  const userTier = isNewUser ? 'Pending' : 'Legacy Fellow';
  const hasPublishingRights = userTier === 'Legacy Fellow' || userTier === 'Senior Alumni';

  // State Management
  const [serviceRecordFile, setServiceRecordFile] = useState<string | null>(null);
  const [selectedLanguage, setSelectedLanguage] = useState<string>('All');
  const [events, setEvents] = useState<AppEvent[]>(MOCK_EVENTS);
  const [forumTopics, setForumTopics] = useState<(ForumTopic & { startDocument?: string })[]>(FORUM_TOPICS);
  const [isHostingEvent, setIsHostingEvent] = useState(false);
  const [isCreatingTopic, setIsCreatingTopic] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<AppEvent | null>(null);
  const [rsvpToast, setRsvpToast] = useState<string | null>(null);

  // Form States
  const [newTopic, setNewTopic] = useState({ title: '', category: '', description: '', documentName: '' });
  const [newEvent, setNewEvent] = useState({ title: '', description: '', location: '', date: '', time: '', type: 'Social' as any, maxGuests: '' });

  useEffect(() => {
    if (rsvpToast) {
      const timer = setTimeout(() => setRsvpToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [rsvpToast]);

  const handleCreateTopic = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTopic.title || !newTopic.description) return;

    const topicToAdd: ForumTopic & { startDocument?: string } = {
      id: Date.now().toString(),
      category: newTopic.category || 'General Discussion',
      title: newTopic.title,
      description: newTopic.description,
      activeCount: 1,
      lastActive: 'Just now',
      startDocument: newTopic.documentName || undefined
    };

    setForumTopics([topicToAdd, ...forumTopics]);
    setIsCreatingTopic(false);
    setNewTopic({ title: '', category: '', description: '', documentName: '' });
    setRsvpToast("Discussion started successfully!");
  };

  const handleCreateEvent = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newEvent.title || !newEvent.date || !newEvent.time) return;

    const eventToAdd: AppEvent = {
      id: Date.now().toString(),
      title: newEvent.title,
      description: newEvent.description,
      location: newEvent.location,
      date: newEvent.date,
      time: newEvent.time,
      type: newEvent.type,
      host: 'Ross Halliday', 
      attendees: 1,
      maxGuests: newEvent.maxGuests ? parseInt(newEvent.maxGuests) : undefined,
      isRsvped: true 
    };

    setEvents([...events, eventToAdd]);
    setIsHostingEvent(false);
    setNewEvent({ title: '', description: '', location: '', date: '', time: '', type: 'Social', maxGuests: '' });
    setRsvpToast("Event created successfully!");
  };

  const handleRSVP = (eventId: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    setEvents(prevEvents => prevEvents.map(event => {
      if (event.id === eventId) {
        const isJoining = !event.isRsvped;
        if (isJoining && event.maxGuests && event.attendees >= event.maxGuests) {
           setRsvpToast("Sorry, this event is full.");
           return event;
        }
        setRsvpToast(isJoining ? `RSVP confirmed` : `RSVP cancelled`);
        return {
          ...event,
          isRsvped: isJoining,
          attendees: isJoining ? event.attendees + 1 : event.attendees - 1
        };
      }
      return event;
    }));
  };

  const SidebarItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => {
    if (isNewUser && view !== ViewState.VAULT_VERIFICATION) {
      return (
        <div className="w-full flex items-center space-x-3 px-6 py-4 border-l-4 border-transparent text-stone-600 cursor-not-allowed opacity-50 rtl:border-l-0 rtl:border-r-4">
          <Icon className="w-5 h-5 rtl:ml-3" />
          <span className="uppercase tracking-widest text-xs font-semibold">{label}</span>
          <Lock className="w-3 h-3 ml-auto opacity-50 rtl:ml-0 rtl:mr-auto" />
        </div>
      );
    }

    return (
      <button 
        onClick={() => {
          onNavigate(view);
          if (view !== ViewState.VAULT_EVENTS) setIsHostingEvent(false);
          if (view !== ViewState.VAULT_FORUM) {
             setActiveTopic(null);
             setIsCreatingTopic(false);
          }
        }}
        className={`w-full flex items-center space-x-3 px-6 py-4 transition-all duration-300 border-l-4 rtl:border-l-0 rtl:border-r-4 ${
          currentView === view 
            ? 'bg-vault-amber/10 border-vault-amber text-vault-amber' 
            : 'border-transparent text-stone-400 hover:text-stone-200 hover:bg-white/5'
        }`}
      >
        <Icon className="w-5 h-5 rtl:ml-3" />
        <span className="uppercase tracking-widest text-xs font-semibold">{label}</span>
      </button>
    );
  };

  const renderContent = () => {
    switch (currentView) {
      case ViewState.VAULT_VERIFICATION:
        return (
          <div className="max-w-4xl mx-auto">
             <div className="mb-10 text-center">
                <ShieldCheck className="w-16 h-16 text-vault-amber mx-auto mb-4" />
                <h1 className="text-4xl font-serif text-vault-mahogany mb-2">Verification Anteroom</h1>
                <p className="text-stone-600 max-w-xl mx-auto">Welcome to IAN. To ensure the integrity of our fellowship, we require identity verification.</p>
             </div>
             <div className="bg-white border border-stone-200 shadow-sm rounded-sm p-8">
                <div className="border-2 border-dashed border-stone-300 rounded-lg p-10 text-center hover:bg-stone-50 cursor-pointer relative">
                  <input type="file" className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={(e) => e.target.files && setServiceRecordFile(e.target.files[0].name)} />
                  {serviceRecordFile ? (
                    <div className="text-green-700">
                      <FileCheck className="w-12 h-12 mx-auto mb-3" />
                      <span className="font-bold">{serviceRecordFile}</span>
                    </div>
                  ) : (
                    <div className="text-stone-400">
                      <Upload className="w-12 h-12 mx-auto mb-3" />
                      <span className="font-bold">Upload Service Record</span>
                    </div>
                  )}
                </div>
             </div>
          </div>
        );

      case ViewState.VAULT_FORUM:
        if (isCreatingTopic) {
          return (
            <div className="max-w-2xl mx-auto">
               <button onClick={() => setIsCreatingTopic(false)} className="flex items-center text-stone-500 text-xs uppercase tracking-widest mb-6 hover:text-vault-mahogany">
                 <ArrowLeft className="w-4 h-4 mr-1 rtl:mr-0 rtl:ml-1 rtl:rotate-180" /> Back to Briefing Room
               </button>
               <div className="bg-white p-8 border-t-4 border-vault-mahogany shadow-md rounded-sm">
                 <h2 className="text-2xl font-serif text-vault-mahogany mb-6">Start New Research Discussion</h2>
                 <form onSubmit={handleCreateTopic} className="space-y-6">
                    <div>
                      <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Subject / Title</label>
                      <input type="text" required value={newTopic.title} onChange={e => setNewTopic({...newTopic, title: e.target.value})} className="w-full border border-stone-300 p-3 bg-stone-50 focus:border-vault-mahogany focus:outline-none font-serif text-lg" placeholder="e.g. Case Study: Cross-border Financial Laundering" />
                    </div>
                    <div>
                      <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Category</label>
                      <select value={newTopic.category} onChange={e => setNewTopic({...newTopic, category: e.target.value})} className="w-full border border-stone-300 p-3 bg-stone-50 focus:border-vault-mahogany focus:outline-none">
                        <option value="Operational History">Operational History</option>
                        <option value="Global Crime Trends">Global Crime Trends</option>
                        <option value="Institutional Memory">Institutional Memory</option>
                        <option value="Spirit of the Charter">Spirit of the Charter</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Discussion Opening / Summary</label>
                      <textarea required value={newTopic.description} onChange={e => setNewTopic({...newTopic, description: e.target.value})} className="w-full border border-stone-300 p-3 bg-stone-50 focus:border-vault-mahogany focus:outline-none min-h-[120px]" placeholder="Provide a detailed starting point for colleagues..." />
                    </div>
                    <div>
                      <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Attach Starting Document (Optional)</label>
                      <div className="flex items-center space-x-4">
                         <label className="cursor-pointer bg-stone-100 border border-stone-300 px-4 py-2 rounded-sm text-xs uppercase tracking-widest hover:bg-stone-200 transition-all flex items-center">
                            <Paperclip className="w-3 h-3 mr-2" />
                            <span>{newTopic.documentName ? 'Change File' : 'Choose File'}</span>
                            <input type="file" className="hidden" onChange={e => e.target.files && setNewTopic({...newTopic, documentName: e.target.files[0].name})} />
                         </label>
                         {newTopic.documentName && <span className="text-xs text-green-700 font-bold">{newTopic.documentName}</span>}
                      </div>
                    </div>
                    <div className="pt-4 border-t border-stone-100 flex justify-end space-x-4">
                       <button type="button" onClick={() => setIsCreatingTopic(false)} className="px-6 py-3 text-xs uppercase tracking-widest text-stone-500">Cancel</button>
                       <button type="submit" className="bg-vault-mahogany text-white px-8 py-3 text-xs uppercase tracking-widest hover:bg-stone-800 transition-colors shadow-sm">Initialize Research Topic</button>
                    </div>
                 </form>
               </div>
            </div>
          );
        }

        if (activeTopic) {
          return (
            <div className="max-w-4xl mx-auto">
               <button onClick={() => setActiveTopic(null)} className="flex items-center text-stone-500 text-xs uppercase tracking-widest mb-6 hover:text-vault-mahogany transition-colors">
                 <ArrowLeft className="w-4 h-4 mr-1 rtl:mr-0 rtl:ml-1 rtl:rotate-180" /> Back to Briefing Room
               </button>
               <div className="bg-white p-8 border-b-4 border-vault-amber shadow-sm mb-8">
                  <span className="text-[10px] uppercase tracking-widest bg-stone-100 px-2 py-1 text-stone-500 rounded-sm">
                    {activeTopic.category}
                  </span>
                  <h2 className="text-3xl font-serif text-vault-mahogany mt-4 mb-2">{activeTopic.title}</h2>
                  <p className="text-stone-700 font-serif text-lg leading-relaxed mb-6">{activeTopic.description}</p>

                  {activeTopic.startDocument && (
                    <div className="bg-vault-amber/5 border border-vault-amber/30 p-4 rounded-sm flex items-center justify-between">
                       <div className="flex items-center space-x-3">
                          <FileText className="w-5 h-5 text-vault-amber" />
                          <div className="text-sm">
                             <p className="font-bold text-vault-mahogany">Primary Source Document</p>
                             <p className="text-stone-500 text-xs">{activeTopic.startDocument}</p>
                          </div>
                       </div>
                       <button className="text-xs uppercase tracking-widest font-bold text-vault-mahogany hover:underline">Download Archive File</button>
                    </div>
                  )}
               </div>
               <div className="space-y-6">
                  {MOCK_FORUM_POSTS.map(post => (
                    <div key={post.id} className="bg-white border border-stone-200 rounded-sm p-6 shadow-sm">
                       <div className="flex items-center justify-between mb-4">
                          <div className="flex items-center space-x-3 rtl:space-x-reverse">
                             <div className="w-8 h-8 rounded-full bg-vault-charcoal text-vault-amber flex items-center justify-center font-bold text-xs">{post.author.charAt(0)}</div>
                             <div>
                               <p className="text-sm font-bold text-vault-mahogany">{post.author}</p>
                               <p className="text-[10px] uppercase text-stone-400">{post.role}</p>
                             </div>
                          </div>
                          <span className="text-xs text-stone-400">{post.timestamp}</span>
                       </div>
                       <p className="text-stone-700 leading-relaxed mb-4">{post.content}</p>
                    </div>
                  ))}
               </div>
            </div>
          );
        }

        return (
          <div className="max-w-6xl mx-auto">
            <div className="flex justify-between items-end mb-8 border-b border-stone-200 pb-4">
              <div>
                <h2 className="text-3xl font-serif text-vault-mahogany mb-2">{t('nav.briefing')}</h2>
                <p className="text-stone-600">Discussion channels dedicated to the pillars of international cooperation.</p>
              </div>
              {hasPublishingRights && (
                <button onClick={() => setIsCreatingTopic(true)} className="bg-vault-mahogany text-vault-amber px-4 py-2 text-xs uppercase tracking-wider rounded-sm flex items-center space-x-2 hover:bg-stone-800 transition-colors shadow-sm">
                   <PlusCircle className="w-4 h-4" />
                   <span>Start Discussion</span>
                </button>
              )}
            </div>
            <div className="grid gap-4">
              {forumTopics.map((topic) => (
                <div key={topic.id} onClick={() => setActiveTopic(topic)} className="bg-white p-6 rounded-sm border-l-4 border-vault-amber shadow-sm hover:shadow-md transition-all cursor-pointer group rtl:border-l-0 rtl:border-r-4">
                  <div className="flex justify-between items-start">
                    <div>
                      <span className="text-[10px] uppercase tracking-widest text-vault-amber font-bold bg-vault-charcoal px-2 py-1 rounded-sm mb-2 inline-block">
                        {topic.category}
                      </span>
                      <h3 className="text-xl font-serif text-vault-mahogany font-semibold group-hover:text-vault-amber transition-colors">
                        {topic.title}
                        {topic.startDocument && <Paperclip className="w-3 h-3 ml-2 inline text-stone-400" />}
                      </h3>
                      <p className="text-stone-600 mt-2 text-sm line-clamp-2">{topic.description}</p>
                    </div>
                    <div className="text-right rtl:text-left shrink-0 ml-4">
                       <div className="flex items-center space-x-1 text-stone-400 text-xs">
                         <Users className="w-3 h-3" />
                         <span>{topic.activeCount} active</span>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );

      case ViewState.VAULT_EVENTS:
        if (isHostingEvent) {
          return (
            <div className="max-w-2xl mx-auto">
               <button onClick={() => setIsHostingEvent(false)} className="flex items-center text-stone-500 text-xs uppercase tracking-widest mb-6 hover:text-vault-mahogany">
                 <ArrowLeft className="w-4 h-4 mr-1 rtl:mr-0 rtl:ml-1 rtl:rotate-180" /> Back to Calendar
               </button>
               <div className="bg-white p-8 border-t-4 border-vault-amber shadow-md rounded-sm">
                 <h2 className="text-2xl font-serif text-vault-mahogany mb-6">Host a Fellowship Event</h2>
                 <form onSubmit={handleCreateEvent} className="space-y-6">
                    <div>
                      <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Event Title</label>
                      <input type="text" required value={newEvent.title} onChange={e => setNewEvent({...newEvent, title: e.target.value})} className="w-full border border-stone-300 p-3 bg-stone-50 focus:border-vault-mahogany focus:outline-none font-serif text-lg" />
                    </div>
                    <div className="grid grid-cols-2 gap-6">
                       <input type="date" required value={newEvent.date} onChange={e => setNewEvent({...newEvent, date: e.target.value})} className="border p-3" />
                       <input type="time" required value={newEvent.time} onChange={e => setNewEvent({...newEvent, time: e.target.value})} className="border p-3" />
                    </div>
                    <button type="submit" className="w-full bg-vault-mahogany text-white py-3 uppercase tracking-widest text-sm hover:bg-stone-800 transition-colors shadow-sm">Schedule Event</button>
                 </form>
               </div>
            </div>
          );
        }

        return (
          <div className="max-w-6xl mx-auto relative">
            {rsvpToast && (
              <div className="fixed top-20 right-8 z-[100] bg-vault-mahogany text-vault-amber px-6 py-3 rounded-sm shadow-2xl flex items-center space-x-3 border border-vault-amber animate-bounce-short">
                <CheckCircle2 className="w-5 h-5" />
                <span className="text-sm font-bold uppercase tracking-widest">{rsvpToast}</span>
              </div>
            )}
            <div className="flex justify-between items-end mb-8">
               <div>
                  <h2 className="text-3xl font-serif text-vault-mahogany mb-2">Fellowship Calendar</h2>
                  <p className="text-stone-600">Reunions and briefings.</p>
               </div>
               {hasPublishingRights && (
                 <button onClick={() => setIsHostingEvent(true)} className="bg-vault-mahogany text-vault-amber px-4 py-2 text-xs uppercase tracking-wider rounded-sm flex items-center space-x-2 hover:bg-stone-800 transition-colors shadow-sm">
                   <PlusCircle className="w-4 h-4" />
                   <span>Host Event</span>
                 </button>
               )}
            </div>

            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
               {events.map(event => (
                 <div key={event.id} onClick={() => setSelectedEvent(event)} className="bg-white border border-stone-200 rounded-sm p-6 relative group hover:border-vault-amber transition-colors shadow-sm cursor-pointer">
                    <div className="inline-block px-2 py-1 bg-stone-100 text-[10px] uppercase tracking-widest text-stone-500 rounded-sm mb-4">{event.type}</div>
                    <h3 className="text-xl font-serif text-vault-mahogany mb-2">{event.title}</h3>
                    <div className="space-y-2 text-sm text-stone-600 mb-6">
                       <div className="flex items-center"><Calendar className="w-4 h-4 mr-2 opacity-70" /><span>{event.date} • {event.time}</span></div>
                       <div className="flex items-center"><Users className="w-4 h-4 mr-2 opacity-70" /><span>Hosted by {event.host}</span></div>
                    </div>
                    <div className="flex justify-between items-center border-t border-stone-100 pt-4">
                       <span className="text-xs text-stone-500">{event.attendees} Attending</span>
                       <button onClick={(e) => handleRSVP(event.id, e)} className={`text-xs uppercase tracking-wider font-bold transition-colors ${event.isRsvped ? 'text-green-600' : 'text-vault-mahogany'}`}>
                         {event.isRsvped ? 'Confirmed' : 'RSVP Now'}
                       </button>
                    </div>
                 </div>
               ))}
            </div>

            {selectedEvent && (
              <div className="fixed inset-0 z-[110] bg-black/60 flex items-center justify-center p-6 backdrop-blur-sm">
                 <div className="bg-vault-paper w-full max-w-2xl border-4 border-vault-mahogany rounded-lg overflow-hidden flex flex-col shadow-2xl animate-fade-in-up">
                    <div className="bg-vault-mahogany p-6 flex justify-between items-start">
                       <h2 className="text-3xl font-serif text-vault-amber">{selectedEvent.title}</h2>
                       <button onClick={() => setSelectedEvent(null)} className="text-vault-amber"><X className="w-8 h-8" /></button>
                    </div>
                    <div className="p-8 font-serif text-stone-800 text-lg">
                       <div className="grid grid-cols-2 gap-4 mb-6">
                          <div><h4 className="text-[10px] uppercase tracking-widest text-stone-400">Date & Time</h4><p className="font-bold">{selectedEvent.date} @ {selectedEvent.time}</p></div>
                          <div><h4 className="text-[10px] uppercase tracking-widest text-stone-400">Location</h4><p className="font-bold">{selectedEvent.location || "Secure Briefing Room"}</p></div>
                       </div>
                       <p className="leading-relaxed">{selectedEvent.description}</p>
                    </div>
                    <div className="p-6 bg-stone-100 border-t border-stone-200 flex justify-end">
                       <button onClick={() => handleRSVP(selectedEvent.id)} className="bg-vault-mahogany text-vault-amber px-8 py-3 uppercase tracking-widest text-sm font-bold shadow-md">
                          {selectedEvent.isRsvped ? 'Cancel RSVP' : 'Confirm Attendance'}
                       </button>
                    </div>
                 </div>
              </div>
            )}
          </div>
        );

      case ViewState.VAULT_DIRECTORY:
        const filteredMembers = selectedLanguage === 'All' 
          ? MOCK_MEMBERS 
          : MOCK_MEMBERS.filter(m => m.languages.includes(selectedLanguage));
        return (
          <div className="max-w-6xl mx-auto">
             <div className="flex justify-between items-end mb-8 border-b border-vault-mahogany/20 pb-4">
              <div>
                <h2 className="text-3xl font-serif text-vault-mahogany">Expertise Directory</h2>
                <p className="text-stone-600 mt-1">Connect with colleagues based on pillars and era.</p>
              </div>
              <div className="flex items-center space-x-3 rtl:space-x-reverse">
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-white border border-stone-300 rounded-sm px-3 py-2 text-xs uppercase tracking-wider">
                   <option value="All">All Languages</option>
                   {INTERPOL_LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>
             </div>
             <div className="grid md:grid-cols-2 gap-6">
               {filteredMembers.map((member: Member) => (
                 <div key={member.id} className="bg-white p-6 rounded-sm shadow-sm border border-stone-200 flex space-x-6 hover:shadow-md transition-shadow">
                    <img src={member.avatarUrl} alt={member.name} className="w-24 h-24 object-cover grayscale rounded-sm" />
                    <div className="flex-1">
                      <div className="flex justify-between items-start mb-2">
                        <h3 className="text-lg font-serif text-vault-mahogany font-bold flex items-center">
                          {member.name} {member.verified && <BadgeCheck className="w-4 h-4 text-green-600 ml-2" />}
                        </h3>
                        <span className="text-[10px] uppercase tracking-wider border border-stone-300 px-2 py-0.5 rounded-full text-stone-500 bg-stone-50">{member.role}</span>
                      </div>
                      <p className="text-xs text-stone-500 mb-2">{member.location} • {member.years}</p>
                      <p className="text-xs italic text-stone-600 mb-4">{member.pillars.join(', ')}</p>
                      <button className="w-full py-2 bg-vault-mahogany text-white text-xs uppercase tracking-widest hover:bg-stone-800 transition-colors">Request Connection</button>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        );

      case ViewState.VAULT_ARCHIE:
        return (
          <div className="max-w-3xl mx-auto">
             <div className="mb-8 text-center"><h2 className="text-3xl font-serif text-vault-mahogany mb-2">The Concierge</h2><p className="text-stone-600 italic">"How can I help you navigate the fellowship today?"</p></div>
             <Archie />
          </div>
        );

      case ViewState.VAULT_WELLBEING:
        return (
          <div className="max-w-4xl mx-auto text-center py-12">
            <Heart className="w-16 h-16 text-vault-mahogany mx-auto mb-6 opacity-80" />
            <h2 className="text-4xl font-serif text-vault-mahogany mb-6">The Battle Buddy Program</h2>
            <div className="bg-white p-8 border-t-4 border-vault-amber shadow-sm text-left max-w-2xl mx-auto">
              <p className="text-lg text-stone-700 mb-6 font-serif">"We match retirees who served in similar regions for private check-ins. No metrics, no marketing, just healing."</p>
              <button className="w-full bg-vault-mahogany text-white py-3 uppercase tracking-widest text-sm hover:bg-stone-800 transition-colors">Request a Match</button>
            </div>
          </div>
        );

      case ViewState.VAULT_MEMBERSHIP:
        return (
          <div className="max-w-6xl mx-auto">
             <h2 className="text-3xl font-serif text-vault-mahogany mb-8">My Membership</h2>
             <div className="grid md:grid-cols-3 gap-8">
              {MEMBERSHIP_TIERS.map((tier) => {
                const isCurrent = tier.name === userTier;
                return (
                  <div key={tier.name} className={`bg-white border p-8 shadow-sm flex flex-col relative ${isCurrent ? 'border-vault-mahogany ring-1 ring-vault-mahogany' : 'border-stone-200'}`}>
