                    <div className="text-3xl font-bold mb-6">{tier.fee}</div>
                    <ul className="space-y-3 mb-8 flex-1">
                      {tier.benefits.map((b, i) => <li key={i} className="flex items-start text-sm text-stone-600"><Award className="w-4 h-4 mr-3 text-vault-amber" />{b}</li>)}
