                    <button className={`w-full py-3 uppercase text-sm tracking-widest transition-colors ${isCurrent ? 'bg-stone-100 text-stone-400 cursor-default' : 'border border-vault-mahogany text-vault-mahogany hover:bg-vault-mahogany hover:text-white'}`} disabled={isCurrent}>{isCurrent ? 'Active' : 'Upgrade'}</button>
                  </div>
