      default: // DASHBOARD
        return (
          <div className="max-w-5xl mx-auto">
            <h1 className="text-4xl font-serif text-vault-mahogany mb-8">{t('vault.welcome')}</h1>
            <div className="grid md:grid-cols-3 gap-6">
