import { GoogleGenAI } from "@google/genai";
import { ARCHIE_SYSTEM_INSTRUCTION } from '../constants';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Archie's Primary Message Handler
 * Uses gemini-3-flash-preview with googleSearch tool.
 */
export const sendMessageToArchie = async (message: string, history: {role: 'user' | 'model', parts: { text: string }[]}[] = []) => {
  try {
    const model = 'gemini-3-flash-preview'; 

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        ...history.map(h => ({ role: h.role, parts: h.parts })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: ARCHIE_SYSTEM_INSTRUCTION,
        temperature: 0.7,
        tools: [{ googleSearch: {} }]
      },
    });

    return {
      text: response.text,
      groundingChunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Archie Error:", error);
    return { text: "I apologize, the line is crackling. I cannot retrieve that data right now.", groundingChunks: [] };
  }
};

/**
 * Deep Research Analysis (Thinking Mode)
 * Uses gemini-3-pro-preview with thinkingBudget for complex reasoning.
 */
export const analyzeResearchTopic = async (topicTitle: string, content: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Perform a deep institutional analysis on the following discussion topic for our alumni network. 
      Identify historical precedents, compliance with ICPO Article 3, and provide a 3-point summary for the Board of Directors.

      TOPIC: ${topicTitle}
      CONTENT: ${content}`,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        systemInstruction: "You are the IAN Vault Oracle. Your role is to provide high-level strategic reasoning to retired officials."
      }
    });

    return response.text;
  } catch (error) {
    console.error("Analysis Error:", error);
    return "The deep analysis engine is currently undergoing maintenance.";
  }
};

