               <div className="bg-white p-8 border-b-4 border-vault-amber shadow-sm mb-8">
                  <div className="flex justify-between items-start mb-4">
                    <span className="text-[10px] uppercase tracking-widest bg-stone-100 px-2 py-1 text-stone-500 rounded-sm">
                      {activeTopic.category}
                    </span>
                    <button 
                      onClick={handleRunAiAnalysis} 
                      disabled={isAnalyzing}
                      className="bg-vault-amber text-vault-mahogany px-3 py-1.5 rounded-sm hover:bg-vault-amber/80 transition-all disabled:opacity-50 flex items-center space-x-2 text-xs uppercase font-bold tracking-widest shadow-sm"
                    >
                      {isAnalyzing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                      <span>Deep Analysis</span>
                    </button>
                  </div>
                  <h2 className="text-3xl font-serif text-vault-mahogany mb-4">{activeTopic.title}</h2>
                  <p className="text-stone-700 font-serif text-lg leading-relaxed mb-6">{activeTopic.description}</p>

                  {activeTopic.startDocument && (
                    <div className="bg-vault-amber/5 border border-vault-amber/30 p-4 rounded-sm flex items-center justify-between mb-6">
                       <div className="flex items-center space-x-3">
                          <FileText className="w-5 h-5 text-vault-amber" />
                          <div className="text-sm">
                             <p className="font-bold text-vault-mahogany">Primary Source Document</p>
                             <p className="text-stone-500 text-xs">{activeTopic.startDocument}</p>
                          </div>
                       </div>
                       <button className="text-xs uppercase tracking-widest font-bold text-vault-mahogany hover:underline">Download Archive File</button>
                    </div>
                  )}

                  {aiAnalysis && (
                    <div className="bg-vault-charcoal text-stone-200 p-6 rounded-sm border-l-4 border-vault-amber animate-fade-in-up shadow-inner">
                       <div className="flex items-center space-x-2 text-vault-amber mb-3">
                          <Sparkles className="w-4 h-4" />
                          <span className="text-[10px] uppercase tracking-[0.2em] font-bold">Research Intelligence Output</span>
                       </div>
                       <div className="text-sm font-serif leading-relaxed whitespace-pre-wrap opacity-90">
                          {aiAnalysis}
                       </div>
                    </div>
                  )}
               </div>

               <div className="space-y-6">
                  {MOCK_FORUM_POSTS.map(post => (
                    <div key={post.id} className="bg-white border border-stone-200 rounded-sm p-6 shadow-sm">
                       <div className="flex items-center justify-between mb-4">
                          <div className="flex items-center space-x-3 rtl:space-x-reverse">
                             <div className="w-8 h-8 rounded-full bg-vault-charcoal text-vault-amber flex items-center justify-center font-bold text-xs">{post.author.charAt(0)}</div>
                             <div>
                               <p className="text-sm font-bold text-vault-mahogany">{post.author}</p>
                               <p className="text-[10px] uppercase text-stone-400">{post.role}</p>
                             </div>
                          </div>
                          <span className="text-xs text-stone-400">{post.timestamp}</span>
                       </div>
                       <p className="text-stone-700 leading-relaxed mb-4">{post.content}</p>
                    </div>
                  ))}
               </div>
            </div>
          );
        }

        return (
          <div className="max-w-6xl mx-auto">
            <div className="flex justify-between items-end mb-8 border-b border-stone-200 pb-4">
              <div>
                <h2 className="text-3xl font-serif text-vault-mahogany mb-2">{t('nav.briefing')}</h2>
                <p className="text-stone-600">Private discussion channels for institutional memory and expertise.</p>
              </div>
              {hasPublishingRights && (
                <button onClick={() => setIsCreatingTopic(true)} className="bg-vault-mahogany text-vault-amber px-4 py-2 text-xs uppercase tracking-wider rounded-sm flex items-center space-x-2 hover:bg-stone-800 transition-colors shadow-sm">
                   <PlusCircle className="w-4 h-4" />
                   <span>Start Discussion</span>
                </button>
              )}
            </div>
            <div className="grid gap-4">
              {forumTopics.map((topic) => (
                <div key={topic.id} onClick={() => setActiveTopic(topic)} className="bg-white p-6 rounded-sm border-l-4 border-vault-amber shadow-sm hover:shadow-md transition-all cursor-pointer group rtl:border-l-0 rtl:border-r-4">
                  <div className="flex justify-between items-start">
                    <div>
                      <span className="text-[10px] uppercase tracking-widest text-vault-amber font-bold bg-vault-charcoal px-2 py-1 rounded-sm mb-2 inline-block">
                        {topic.category}
                      </span>
                      <h3 className="text-xl font-serif text-vault-mahogany font-semibold group-hover:text-vault-amber transition-colors">
                        {topic.title}
                        {topic.startDocument && <Paperclip className="w-3 h-3 ml-2 inline text-stone-400" />}
                      </h3>
                      <p className="text-stone-600 mt-2 text-sm line-clamp-2">{topic.description}</p>
                    </div>
                    <div className="text-right shrink-0 ml-4">
                       <div className="flex items-center space-x-1 text-stone-400 text-xs">
                         <Users className="w-3 h-3" />
                         <span>{topic.activeCount} active</span>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );

      case ViewState.VAULT_DIRECTORY:
        const filteredMembers = selectedLanguage === 'All' 
          ? MOCK_MEMBERS 
          : MOCK_MEMBERS.filter(m => m.languages.includes(selectedLanguage));
        return (
          <div className="max-w-6xl mx-auto">
             <div className="flex justify-between items-end mb-8 border-b border-vault-mahogany/20 pb-4">
              <div>
                <h2 className="text-3xl font-serif text-vault-mahogany">Expertise Directory</h2>
                <p className="text-stone-600 mt-1">Connect with colleagues based on operational background.</p>
              </div>
              <div className="flex items-center space-x-3">
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-white border border-stone-300 rounded-sm px-3 py-2 text-xs uppercase tracking-wider">
                   <option value="All">All Languages</option>
                   {INTERPOL_LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>
             </div>
             <div className="grid md:grid-cols-2 gap-6">
               {filteredMembers.map((member: Member) => (
                 <div key={member.id} className="bg-white p-6 rounded-sm shadow-sm border border-stone-200 flex space-x-6 hover:shadow-md transition-shadow">
                    <img src={member.avatarUrl} alt={member.name} className="w-24 h-24 object-cover grayscale rounded-sm border border-stone-200" />
                    <div className="flex-1">
                      <div className="flex justify-between items-start mb-2">
                        <h3 className="text-lg font-serif text-vault-mahogany font-bold flex items-center">
                          {member.name} {member.verified && <BadgeCheck className="w-4 h-4 text-green-600 ml-2" fill="currentColor" stroke="white" />}
                        </h3>
                        <span className="text-[10px] uppercase tracking-wider border border-stone-300 px-2 py-0.5 rounded-full text-stone-500 bg-stone-50">{member.role}</span>
                      </div>
                      <p className="text-xs text-stone-500 mb-2">{member.location} • {member.years}</p>
                      <p className="text-xs italic text-stone-600 mb-4">{member.pillars.join(', ')}</p>
                      <button className="w-full py-2 bg-vault-mahogany text-white text-xs uppercase tracking-widest hover:bg-stone-800 transition-colors">Request Private Channel</button>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        );

      case ViewState.VAULT_EVENTS:
        return (
          <div className="max-w-6xl mx-auto">
            <h2 className="text-3xl font-serif text-vault-mahogany mb-8">Fellowship Calendar</h2>
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
               {events.map(event => (
                 <div key={event.id} className="bg-white border border-stone-200 rounded-sm p-6 shadow-sm">
                    <div className="text-[10px] uppercase text-stone-400 mb-2">{event.type}</div>
                    <h3 className="text-xl font-serif text-vault-mahogany mb-2">{event.title}</h3>
                    <div className="text-sm text-stone-500 mb-4 flex items-center">
                      <Clock className="w-3 h-3 mr-2" />
                      {event.date} • {event.time}
                    </div>
                    <p className="text-sm text-stone-600 mb-4 line-clamp-2">{event.description}</p>
                    <button className="w-full py-2 border border-vault-mahogany text-vault-mahogany text-xs uppercase tracking-widest hover:bg-vault-mahogany hover:text-white transition-colors">RSVP</button>
                 </div>
               ))}
            </div>
          </div>
        );

      case ViewState.VAULT_WELLBEING:
        return (
          <div className="max-w-4xl mx-auto py-12 text-center">
            <Heart className="w-16 h-16 text-vault-mahogany mx-auto mb-6" />
            <h2 className="text-4xl font-serif text-vault-mahogany mb-4">The Battle Buddy Program</h2>
            <p className="text-lg text-stone-600 mb-8 max-w-2xl mx-auto font-serif">
              "Transitioning from service is a journey. We match retirees who served in similar roles for private peer-to-peer check-ins."
            </p>
            <div className="bg-white p-8 border border-stone-200 shadow-sm max-w-lg mx-auto">
              <button className="w-full bg-vault-mahogany text-white py-3 uppercase tracking-widest text-sm hover:bg-stone-800 transition-colors">Connect with a Buddy</button>
            </div>
          </div>
        );

      case ViewState.VAULT_MEMBERSHIP:
        return (
          <div className="max-w-6xl mx-auto">
             <h2 className="text-3xl font-serif text-vault-mahogany mb-8">My Membership</h2>
             <div className="grid md:grid-cols-3 gap-8">
              {MEMBERSHIP_TIERS.map((tier) => {
                const isCurrent = tier.name === userTier;
                return (
                  <div key={tier.name} className={`bg-white border p-8 shadow-sm flex flex-col relative ${isCurrent ? 'border-vault-mahogany ring-1 ring-vault-mahogany shadow-xl' : 'border-stone-200'}`}>
                    {isCurrent && <div className="absolute top-0 right-0 bg-vault-mahogany text-vault-amber text-[10px] uppercase tracking-widest px-3 py-1 font-bold">Current Plan</div>}
                    <h3 className="text-2xl font-serif text-vault-mahogany mb-1">{tier.name}</h3>
                    <p className="text-stone-500 text-sm uppercase mb-4">{tier.target}</p>
                    <div className="text-3xl font-bold mb-6">{tier.fee}</div>
                    <ul className="space-y-3 mb-8 flex-1">
                      {tier.benefits.map((b, i) => <li key={i} className="flex items-start text-sm text-stone-600"><Award className="w-4 h-4 mr-3 text-vault-amber" />{b}</li>)}
                    </ul>
                    <button className={`w-full py-3 uppercase text-sm tracking-widest transition-colors ${isCurrent ? 'bg-stone-100 text-stone-400 cursor-default' : 'border border-vault-mahogany text-vault-mahogany hover:bg-vault-mahogany hover:text-white'}`} disabled={isCurrent}>{isCurrent ? 'Active' : 'Upgrade'}</button>
                  </div>
                );
              })}
            </div>
          </div>
        );

      case ViewState.VAULT_ARCHIE:
        return (
          <div className="max-w-3xl mx-auto animate-fade-in-up">
             <div className="mb-8 text-center">
               <h2 className="text-3xl font-serif text-vault-mahogany mb-2">The Concierge</h2>
               <p className="text-stone-600 italic">"I am listening. How can I facilitate your connection to the archives today?"</p>
             </div>
             <Archie />
          </div>
        );

      case ViewState.VAULT_DASHBOARD:
      default:
        return (
          <div className="max-w-5xl mx-auto">
            <h1 className="text-4xl font-serif text-vault-mahogany mb-8">{t('vault.welcome')}</h1>
            <div className="grid md:grid-cols-3 gap-6">
               <div onClick={() => onNavigate(ViewState.VAULT_ARCHIE)} className="bg-vault-mahogany text-vault-amber p-6 rounded-lg cursor-pointer hover:bg-stone-800 transition-colors shadow-lg group">
                 <Search className="w-8 h-8 mb-4 group-hover:scale-110 transition-transform" />
                 <h3 className="text-xl font-serif mb-2">{t('vault.quick.archie')}</h3>
                 <p className="text-sm opacity-80">Check current ICPO resolutions via Google Search Grounding.</p>
               </div>
               <div onClick={() => onNavigate(ViewState.VAULT_FORUM)} className="bg-white border border-stone-200 p-6 rounded-lg shadow-sm cursor-pointer hover:border-vault-amber transition-colors">
                 <MessageSquare className="w-8 h-8 text-vault-mahogany mb-4" />
                 <h3 className="text-xl font-serif text-vault-mahogany mb-2">{t('vault.quick.forum')}</h3>
                 <p className="text-sm text-stone-600 mb-4">Deep analysis research topics enabled for your tier.</p>
                 <button className="text-xs uppercase tracking-wider text-vault-amber bg-vault-mahogany px-3 py-1 rounded-full">Enter Room</button>
               </div>
               <div className="bg-gradient-to-br from-red-600 to-red-800 text-white p-6 rounded-lg shadow-sm">
                  <Youtube className="w-8 h-8 mb-4" />
                  <h3 className="text-xl font-serif mb-1">Featured Channel</h3>
                  <p className="text-sm opacity-90 mb-4">Halliday's Podcast: "The Future of Neutrality"</p>
                  <a href="https://www.youtube.com/@HallidaysPodcast" target="_blank" rel="noopener noreferrer" className="inline-flex items-center space-x-2 text-xs uppercase tracking-wider bg-white/20 hover:bg-white/30 px-3 py-2 rounded-sm transition-colors"><ExternalLink className="w-3 h-3" /><span>Watch</span></a>
               </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex min-h-screen bg-stone-50 font-sans text-stone-800 overflow-x-hidden">
      <aside className="w-64 bg-vault-charcoal flex flex-col flex-shrink-0 sticky top-0 h-screen z-[90]">
        <div className="p-6 border-b border-stone-700 text-center">
          <h1 className="text-2xl font-serif text-vault-amber tracking-wider">THE VAULT</h1>
          <p className="text-slate-400 text-[10px] uppercase mt-1">Institutional Custody</p>
        </div>
        <nav className="flex-1 py-8 space-y-2">
           <SidebarItem view={ViewState.VAULT_DASHBOARD} icon={ShieldCheck} label={t('nav.dashboard')} />
           <SidebarItem view={ViewState.VAULT_FORUM} icon={MessageSquare} label={t('nav.briefing')} />
           <SidebarItem view={ViewState.VAULT_EVENTS} icon={Calendar} label={t('nav.calendar')} />
           <SidebarItem view={ViewState.VAULT_DIRECTORY} icon={Users} label={t('nav.directory')} />
           <SidebarItem view={ViewState.VAULT_ARCHIE} icon={Search} label={t('nav.concierge')} />
           <SidebarItem view={ViewState.VAULT_WELLBEING} icon={Heart} label={t('nav.wellbeing')} />
           <SidebarItem view={ViewState.VAULT_MEMBERSHIP} icon={CreditCard} label={t('nav.membership')} />
        </nav>
        <div className="p-6 border-t border-stone-700">
           <div className="flex items-center space-x-3 mb-6">
              <div className="w-8 h-8 bg-vault-amber rounded-full flex items-center justify-center text-vault-mahogany font-bold text-xs">RH</div>
              <div className="text-xs text-stone-300">
                <p className="font-bold">Ross Halliday</p>
                <p className="text-stone-500">Founding Director</p>
              </div>
           </div>
           <button onClick={onLogout} className="flex items-center space-x-2 text-xs uppercase tracking-widest text-stone-400 hover:text-white transition-colors">
             <LogOut className="w-4 h-4" /><span>Logout</span>
           </button>
        </div>
      </aside>
      <main className="flex-1 overflow-y-auto">
         <div className="h-16 bg-white border-b border-stone-200 flex items-center justify-between px-8">
             <div className="relative group">
               <button className="flex items-center space-x-1 hover:text-vault-mahogany text-stone-500 text-xs font-bold uppercase tracking-wider">
                 <Globe className="w-4 h-4 mr-2" /><span>{language.toUpperCase()}</span>
               </button>
               <div className="absolute left-0 mt-2 w-32 bg-white text-slate-800 rounded-sm shadow-xl hidden group-hover:block border border-slate-200 z-50">
                  {(['en', 'fr', 'es', 'ar'] as LanguageCode[]).map((lang) => (
                    <button key={lang} onClick={() => setLanguage(lang)} className="block w-full text-left px-4 py-2 hover:bg-slate-100 text-xs">{lang === 'en' ? 'English' : lang === 'fr' ? 'Français' : lang === 'es' ? 'Español' : 'العربية'}</button>
                  ))}
               </div>
            </div>
            <div className="text-stone-400 text-xs uppercase tracking-widest">Vault Security • ICPO Alumni Network</div>
         </div>
         <div className="p-8 md:p-12">{renderContent()}</div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes fade-in-up { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in-up { animation: fade-in-up 0.4s ease-out forwards; }
        @keyframes bounce-short { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-3px); } }
        .animate-bounce-short { animation: bounce-short 1s ease-in-out infinite; }
      `}} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, Member, AppEvent, ForumPost, ForumTopic, LanguageCode } from '../types';
import { MOCK_MEMBERS, FORUM_TOPICS, MOCK_EVENTS, MOCK_FORUM_POSTS, MEMBERSHIP_TIERS, INTERPOL_LANGUAGES } from '../constants';
import { Archie } from './Archie';
import { analyzeResearchTopic } from '../services/geminiService';
import { 
  Users, Calendar, FileText, Heart, Search, 
  LogOut, ShieldCheck, MessageSquare, Globe,
  Youtube, ExternalLink, PlusCircle, ArrowLeft, BadgeCheck, CreditCard, Award, CheckCircle2, X, Upload, FileCheck, Lock, Paperclip, Sparkles, Loader2,
  // Fix: Added Clock import from lucide-react
  Clock
} from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface VaultProps {
  currentView: ViewState;
  onNavigate: (view: ViewState) => void;
  onLogout: () => void;
  isNewUser?: boolean;
}

export const Vault: React.FC<VaultProps> = ({ currentView, onNavigate, onLogout, isNewUser = false }) => {
  const [activeTopic, setActiveTopic] = useState<ForumTopic | null>(null);
  const { t, language, setLanguage } = useLanguage();

  const userTier: string = isNewUser ? 'Pending' : 'Legacy Fellow';
  const hasPublishingRights = userTier === 'Legacy Fellow' || userTier === 'Senior Alumni';

  const [serviceRecordFile, setServiceRecordFile] = useState<string | null>(null);
  const [selectedLanguage, setSelectedLanguage] = useState<string>('All');
  const [events, setEvents] = useState<AppEvent[]>(MOCK_EVENTS);
  const [forumTopics, setForumTopics] = useState<ForumTopic[]>(FORUM_TOPICS);
  const [isHostingEvent, setIsHostingEvent] = useState(false);
  const [isCreatingTopic, setIsCreatingTopic] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<AppEvent | null>(null);
  const [rsvpToast, setRsvpToast] = useState<string | null>(null);

  // AI Analysis states
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const [newTopic, setNewTopic] = useState({ title: '', category: 'Operational History', description: '', documentName: '' });
  const [newEvent, setNewEvent] = useState({ title: '', description: '', location: '', date: '', time: '', type: 'Social' as any, maxGuests: '' });

  useEffect(() => {
    if (rsvpToast) {
      const timer = setTimeout(() => setRsvpToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [rsvpToast]);

  const handleRunAiAnalysis = async () => {
    if (!activeTopic) return;
    setIsAnalyzing(true);
    const analysis = await analyzeResearchTopic(activeTopic.title, activeTopic.description);
    setAiAnalysis(analysis);
    setIsAnalyzing(false);
  };

  const handleCreateTopic = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTopic.title || !newTopic.description) return;

    const topicToAdd: ForumTopic = {
      id: Date.now().toString(),
      category: newTopic.category,
      title: newTopic.title,
      description: newTopic.description,
      activeCount: 1,
      lastActive: 'Just now',
      startDocument: newTopic.documentName || undefined
    };

    setForumTopics([topicToAdd, ...forumTopics]);
    setIsCreatingTopic(false);
    setNewTopic({ title: '', category: 'Operational History', description: '', documentName: '' });
    setRsvpToast("Discussion initialized successfully.");
  };

  const SidebarItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => {
    if (isNewUser && view !== ViewState.VAULT_VERIFICATION) {
      return (
        <div className="w-full flex items-center space-x-3 px-6 py-4 border-l-4 border-transparent text-stone-600 cursor-not-allowed opacity-50 rtl:border-l-0 rtl:border-r-4">
          <Icon className="w-5 h-5 rtl:ml-3" />
          <span className="uppercase tracking-widest text-xs font-semibold">{label}</span>
          <Lock className="w-3 h-3 ml-auto opacity-50 rtl:ml-0 rtl:mr-auto" />
        </div>
      );
    }

    return (
      <button 
        onClick={() => {
          onNavigate(view);
          if (view !== ViewState.VAULT_FORUM) {
             setActiveTopic(null);
             setIsCreatingTopic(false);
             setAiAnalysis(null);
          }
        }}
        className={`w-full flex items-center space-x-3 px-6 py-4 transition-all duration-300 border-l-4 rtl:border-l-0 rtl:border-r-4 ${
          currentView === view 
            ? 'bg-vault-amber/10 border-vault-amber text-vault-amber' 
            : 'border-transparent text-stone-400 hover:text-stone-200 hover:bg-white/5'
        }`}
      >
        <Icon className="w-5 h-5 rtl:ml-3" />
        <span className="uppercase tracking-widest text-xs font-semibold">{label}</span>
      </button>
    );
  };

  const renderContent = () => {
    switch (currentView) {
      case ViewState.VAULT_VERIFICATION:
        return (
          <div className="max-w-4xl mx-auto">
             <div className="mb-10 text-center">
                <ShieldCheck className="w-16 h-16 text-vault-amber mx-auto mb-4" />
                <h1 className="text-4xl font-serif text-vault-mahogany mb-2">Verification Anteroom</h1>
                <p className="text-stone-600 max-w-xl mx-auto">Welcome to IAN. To ensure the integrity of our fellowship, we require identity verification for all members.</p>
             </div>
             <div className="bg-white border border-stone-200 shadow-sm rounded-sm p-8">
                <div className="border-2 border-dashed border-stone-300 rounded-lg p-10 text-center hover:bg-stone-50 cursor-pointer relative">
                  <input type="file" className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={(e) => e.target.files && setServiceRecordFile(e.target.files[0].name)} />
                  {serviceRecordFile ? (
                    <div className="text-green-700">
                      <FileCheck className="w-12 h-12 mx-auto mb-3" />
                      <span className="font-bold">{serviceRecordFile}</span>
                    </div>
                  ) : (
                    <div className="text-stone-400">
                      <Upload className="w-12 h-12 mx-auto mb-3" />
                      <span className="font-bold">Upload Service Record</span>
                    </div>
                  )}
                </div>
             </div>
          </div>
        );

      case ViewState.VAULT_FORUM:
        if (isCreatingTopic) {
          return (
            <div className="max-w-2xl mx-auto animate-fade-in-up">
               <button onClick={() => setIsCreatingTopic(false)} className="flex items-center text-stone-500 text-xs uppercase tracking-widest mb-6 hover:text-vault-mahogany">
                 <ArrowLeft className="w-4 h-4 mr-1 rtl:mr-0 rtl:ml-1 rtl:rotate-180" /> Back to Briefing Room
               </button>
               <div className="bg-white p-8 border-t-4 border-vault-mahogany shadow-md rounded-sm">
                 <h2 className="text-2xl font-serif text-vault-mahogany mb-6">Start New Research Discussion</h2>
