    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Perform a deep institutional analysis on the following discussion topic for our alumni network. 
      Identify historical precedents, compliance with ICPO Article 3, and provide a 3-point summary for the Board of Directors.

      TOPIC: ${topicTitle}
      CONTENT: ${content}`,
      config: {
        // Balancing thinking budget and output tokens to prevent API internal errors
        thinkingConfig: { thinkingBudget: 16000 },
        maxOutputTokens: 24000, 
        systemInstruction: "You are the IAN Vault Oracle. Your role is to provide high-level strategic reasoning to retired officials."
      }
    });

    return response.text;
  } catch (error) {
    console.debug("Analysis Failed:", error);
    // Fallback message that is more descriptive for the user
    return "The analytical engine encountered a processing error. This usually occurs when the request exceeds institutional memory limits. Please try a more specific query.";
  }
};

