import React, { useState, useEffect } from 'react';
import { ViewState, Member, AppEvent, ForumPost, ForumTopic, LanguageCode, AlumniStory, StoryComment } from '../types';
import { MOCK_MEMBERS, FORUM_TOPICS, MOCK_EVENTS, MOCK_FORUM_POSTS, MEMBERSHIP_TIERS, INTERPOL_LANGUAGES, ALUMNI_STORIES } from '../constants';
import { Archie } from './Archie';
import { analyzeResearchTopic } from '../services/geminiService';
import { 
  Users, Calendar, FileText, Heart, Search, 
  LogOut, ShieldCheck, MessageSquare, Globe,
  Youtube, ExternalLink, PlusCircle, ArrowLeft, BadgeCheck, CreditCard, Award, CheckCircle2, X, Upload, FileCheck, Lock, Paperclip, Sparkles, Loader2,
  Clock, UserCircle, HandHeart, BookOpen, Settings, Check, MessageCircle, Send
} from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface VaultProps {
  currentView: ViewState;
  onNavigate: (view: ViewState) => void;
  onLogout: () => void;
  isNewUser?: boolean;
}

export const Vault: React.FC<VaultProps> = ({ currentView, onNavigate, onLogout, isNewUser = false }) => {
  const [activeTopic, setActiveTopic] = useState<ForumTopic | null>(null);
  const { t, language, setLanguage } = useLanguage();

  const userTier: string = isNewUser ? 'Pending' : 'Legacy Fellow';
  const hasPublishingRights = userTier === 'Legacy Fellow' || userTier === 'Senior Alumni';

  const [serviceRecordFile, setServiceRecordFile] = useState<string | null>(null);
  const [selectedLanguage, setSelectedLanguage] = useState<string>('All');
  const [events, setEvents] = useState<AppEvent[]>(MOCK_EVENTS);
  const [forumTopics, setForumTopics] = useState<ForumTopic[]>(FORUM_TOPICS);
  const [isCreatingTopic, setIsCreatingTopic] = useState(false);
  const [rsvpToast, setRsvpToast] = useState<string | null>(null);

  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const [newTopic, setNewTopic] = useState({ title: '', category: 'Operational History', description: '', documentName: '' });
  const [activeStory, setActiveStory] = useState<AlumniStory | null>(null);

  const [donationAmount, setDonationAmount] = useState<string>('50');
  const [isConnected, setIsConnected] = useState<Record<string, boolean>>({});

  // State for user contributions to stories
  const [adviceInput, setAdviceInput] = useState('');
  const [localStories, setLocalStories] = useState<AlumniStory[]>(ALUMNI_STORIES);

  useEffect(() => {
    if (rsvpToast) {
      const timer = setTimeout(() => setRsvpToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [rsvpToast]);

  const handleRunAiAnalysis = async () => {
    if (!activeTopic) return;
    setIsAnalyzing(true);
    const analysis = await analyzeResearchTopic(activeTopic.title, activeTopic.description);
    setAiAnalysis(analysis);
    setIsAnalyzing(false);
  };

  const handleConnect = (id: string) => {
    setIsConnected(prev => ({ ...prev, [id]: true }));
    setRsvpToast("Connection request transmitted.");
  };

  const handleAddAdvice = () => {
    if (!activeStory || !adviceInput.trim()) return;

    const newComment: StoryComment = {
      id: Date.now().toString(),
      author: 'Ross Halliday', // Mock current user
      role: 'Founding Director',
      text: adviceInput,
      timestamp: 'Just now'
    };

    const updatedStories = localStories.map(s => {
      if (s.id === activeStory.id) {
        return {
          ...s,
          comments: [...(s.comments || []), newComment]
        };
      }
      return s;
    });

    setLocalStories(updatedStories);
    setActiveStory(updatedStories.find(s => s.id === activeStory.id) || null);
    setAdviceInput('');
    setRsvpToast("Advice appended to Archive.");
  };

  const SidebarItem = ({ view, icon: Icon, label }: { view: ViewState, icon: any, label: string }) => {
    const disabled = isNewUser && view !== ViewState.VAULT_VERIFICATION && view !== ViewState.VAULT_DASHBOARD;

    return (
      <button 
        disabled={disabled}
        onClick={() => {
          onNavigate(view);
          setActiveTopic(null);
          setAiAnalysis(null);
          setActiveStory(null);
        }}
        className={`w-full flex items-center space-x-3 px-6 py-4 transition-all duration-300 border-l-4 rtl:border-l-0 rtl:border-r-4 ${
          currentView === view 
            ? 'bg-vault-amber/10 border-vault-amber text-vault-amber' 
            : 'border-transparent text-stone-400 hover:text-stone-200 hover:bg-white/5'
        } ${disabled ? 'opacity-30 cursor-not-allowed' : 'cursor-pointer'}`}
      >
        <Icon className="w-5 h-5 rtl:ml-3" />
        <span className="uppercase tracking-widest text-[10px] font-bold">{label}</span>
      </button>
    );
  };

  const renderContent = () => {
    switch (currentView) {
      case ViewState.VAULT_PROFILE:
        return (
          <div className="max-w-4xl mx-auto animate-fade-in-up">
             <div className="bg-white border border-stone-200 shadow-sm rounded-sm overflow-hidden">
                <div className="h-32 bg-vault-charcoal relative">
                   <div className="absolute -bottom-12 left-8 w-24 h-24 rounded-sm border-4 border-white bg-vault-amber flex items-center justify-center text-vault-mahogany font-bold text-3xl">RH</div>
                </div>
                <div className="pt-16 pb-8 px-8">
                   <div className="flex justify-between items-start mb-6">
                      <div>
                        <h2 className="text-2xl font-serif text-vault-mahogany font-bold">Ross Halliday</h2>
                        <p className="text-stone-500 uppercase tracking-widest text-xs">Founding Director • Board Member</p>
                      </div>
                      <button className="bg-vault-mahogany text-white px-4 py-2 text-[10px] uppercase tracking-widest hover:bg-stone-800 flex items-center space-x-2">
                        <Settings className="w-3 h-3" />
                        <span>Edit Public Identity</span>
                      </button>
                   </div>

                   <div className="grid md:grid-cols-2 gap-8">
                      <div className="space-y-6">
                         <div>
                            <label className="block text-[10px] uppercase tracking-[0.2em] text-stone-400 mb-2 font-bold">Biography</label>
                            <p className="text-stone-700 font-serif leading-relaxed">Dedicated to the preservation of institutional memory and the welfare of former Interpol colleagues worldwide. Serving as the primary architect for the IAN digital ecosystem.</p>
                         </div>
                         <div>
                            <label className="block text-[10px] uppercase tracking-[0.2em] text-stone-400 mb-2 font-bold">Service Record</label>
                            <div className="space-y-2">
                               <div className="flex justify-between text-sm border-b border-stone-100 pb-2">
                                  <span className="text-stone-500">Service Era</span>
                                  <span className="font-bold text-vault-mahogany">1985 - 2015</span>
                               </div>
                               <div className="flex justify-between text-sm border-b border-stone-100 pb-2">
                                  <span className="text-stone-500">Primary Post</span>
                                  <span className="font-bold text-vault-mahogany">Lyon, France</span>
                               </div>
                            </div>
                         </div>
                      </div>
                      <div className="space-y-6">
                         <div>
                            <label className="block text-[10px] uppercase tracking-[0.2em] text-stone-400 mb-2 font-bold">Privacy Settings</label>
                            <div className="space-y-3">
                               <label className="flex items-center space-x-3 cursor-pointer">
                                  <input type="checkbox" checked readOnly className="form-checkbox text-vault-mahogany" />
                                  <span className="text-xs text-stone-600">Show years of service to verified members</span>
                                </label>
                                <label className="flex items-center space-x-3 cursor-pointer">
                                  <input type="checkbox" checked readOnly className="form-checkbox text-vault-mahogany" />
                                  <span className="text-xs text-stone-600">Allow "Connect" requests from peers</span>
                                </label>
                                <label className="flex items-center space-x-3 cursor-pointer">
                                  <input type="checkbox" checked readOnly className="form-checkbox text-vault-mahogany" />
                                  <span className="text-xs text-stone-600">Enable "Mentor" availability badge</span>
                                </label>
                            </div>
                         </div>
                      </div>
                   </div>
                </div>
             </div>
          </div>
        );

      case ViewState.VAULT_GIVING:
        return (
          <div className="max-w-4xl mx-auto py-8">
            <div className="text-center mb-12">
               <HandHeart className="w-16 h-16 text-vault-amber mx-auto mb-4" />
               <h2 className="text-4xl font-serif text-vault-mahogany mb-2">The Legacy Fund</h2>
               <p className="text-stone-600 max-w-xl mx-auto">Supporting the Interpol Academy and the families of those who fell in the line of duty.</p>
            </div>
            <div className="bg-white border border-stone-200 shadow-sm p-10 max-w-2xl mx-auto text-center">
               <h3 className="text-xl font-serif text-vault-mahogany mb-6">Contribute to the Archive</h3>
               <div className="grid grid-cols-4 gap-4 mb-8">
                 {['25', '50', '100', '500'].map(amt => (
                   <button 
                     key={amt} 
                     onClick={() => setDonationAmount(amt)}
                     className={`py-3 border-2 transition-all font-bold ${donationAmount === amt ? 'bg-vault-mahogany text-white border-vault-mahogany' : 'border-stone-200 text-stone-400 hover:border-vault-amber'}`}
                   >
                     ${amt}
                   </button>
                 ))}
               </div>
               <button className="w-full bg-vault-mahogany text-vault-amber py-4 uppercase tracking-[0.2em] text-sm font-bold shadow-lg hover:bg-stone-800 transition-colors">Confirm Contribution</button>
               <p className="mt-6 text-[10px] text-stone-400 uppercase tracking-widest">Secure transaction powered by IAN Treasury</p>
            </div>
          </div>
        );

      case ViewState.VAULT_STORIES:
        if (activeStory) {
          return (
            <div className="max-w-4xl mx-auto animate-fade-in-up">
              <button onClick={() => setActiveStory(null)} className="flex items-center text-stone-400 text-[10px] uppercase font-bold tracking-widest mb-6 hover:text-vault-mahogany">
                <ArrowLeft className="w-4 h-4 mr-1" /> Return to Archives
              </button>
              <div className="bg-white p-10 border-t-8 border-vault-mahogany shadow-xl mb-12">
                 <div className="flex justify-between items-center mb-8 border-b border-stone-100 pb-4">
                    <span className="text-stone-400 font-serif italic">Archive File #{activeStory.id}</span>
                    <span className="text-xs uppercase font-bold text-vault-amber bg-vault-charcoal px-2 py-1">{activeStory.year}</span>
                 </div>
                 <h2 className="text-4xl font-serif text-vault-mahogany mb-6">{activeStory.title}</h2>
                 <p className="text-stone-500 text-xs uppercase tracking-widest mb-8">Author: {activeStory.author}</p>
                 <div className="prose prose-stone font-serif text-xl leading-relaxed text-stone-700 first-letter:text-5xl first-letter:font-bold first-letter:mr-2 first-letter:float-left mb-10 pb-10 border-b border-stone-100">
                   {activeStory.fullContent}
                 </div>

                 {/* Comments/Advice Section */}
                 <div className="bg-vault-paper/50 p-6 border-l-2 border-vault-amber">
                    <h3 className="text-sm uppercase tracking-[0.2em] font-bold text-vault-mahogany mb-6 flex items-center">
                       <MessageCircle className="w-4 h-4 mr-2" /> Institutional Footnotes & Advice
                    </h3>
                    <div className="space-y-6 mb-8">
                       {activeStory.comments && activeStory.comments.length > 0 ? (
                         activeStory.comments.map(comment => (
                           <div key={comment.id} className="border-b border-stone-200 pb-4 last:border-0">
                             <div className="flex justify-between items-start mb-1">
                                <span className="text-xs font-bold text-vault-mahogany">{comment.author} <span className="font-normal text-stone-400">({comment.role})</span></span>
                                <span className="text-[10px] text-stone-400 uppercase">{comment.timestamp}</span>
                             </div>
                             <p className="text-sm text-stone-600 italic font-serif leading-relaxed">"{comment.text}"</p>
                           </div>
                         ))
                       ) : (
                         <p className="text-xs text-stone-400 italic">No footprints left yet. Be the first to advise.</p>
                       )}
                    </div>

                    <div className="mt-6">
                       <label className="block text-[10px] uppercase tracking-widest text-stone-400 mb-2">Leave an Institutional Advice</label>
                       <div className="flex space-x-2">
                          <textarea 
                            value={adviceInput}
                            onChange={(e) => setAdviceInput(e.target.value)}
                            className="flex-1 bg-white border border-stone-300 p-3 text-sm font-serif italic focus:outline-none focus:ring-1 focus:ring-vault-amber"
                            placeholder="Add your perspective to this historical record..."
                            rows={2}
                          />
                          <button 
                            onClick={handleAddAdvice}
                            className="bg-vault-mahogany text-vault-amber px-4 flex flex-col items-center justify-center hover:bg-stone-800 transition-colors"
                          >
                             <Send className="w-4 h-4" />
                             <span className="text-[8px] uppercase mt-1">Submit</span>
                          </button>
                       </div>
                    </div>
                 </div>
              </div>
            </div>
          );
        }
        return (
          <div className="max-w-6xl mx-auto">
             <div className="flex justify-between items-end mb-12 border-b border-stone-200 pb-6">
                <div>
                   <h2 className="text-4xl font-serif text-vault-mahogany">Oral Histories</h2>
                   <p className="text-stone-500">Firsthand accounts of the events that shaped international cooperation.</p>
                </div>
                <BookOpen className="w-8 h-8 text-vault-amber opacity-50" />
             </div>
             <div className="grid md:grid-cols-2 gap-8">
               {localStories.map(story => (
                 <div key={story.id} onClick={() => setActiveStory(story)} className="bg-white p-8 border border-stone-200 hover:border-vault-amber shadow-sm hover:shadow-lg transition-all cursor-pointer group">
                    <div className="flex justify-between items-start mb-2">
                       <div className="text-[10px] uppercase text-stone-400 font-bold tracking-widest">{story.year} • {story.author}</div>
                       <div className="flex items-center text-stone-300 group-hover:text-vault-amber transition-colors">
                          <MessageCircle className="w-3 h-3 mr-1" />
                          <span className="text-[10px]">{story.comments?.length || 0}</span>
                       </div>
                    </div>
                    <h3 className="text-2xl font-serif text-vault-mahogany group-hover:text-vault-amber transition-colors mb-4">{story.title}</h3>
                    <p className="text-stone-600 line-clamp-3 mb-6 leading-relaxed font-serif text-lg italic">"{story.snippet}"</p>
                    <div className="flex flex-wrap gap-2">
                      {story.tags.map(tag => <span key={tag} className="text-[9px] bg-stone-100 text-stone-500 px-2 py-1 uppercase font-bold tracking-tighter">#{tag}</span>)}
                    </div>
                 </div>
               ))}
             </div>
          </div>
        );

      case ViewState.VAULT_DIRECTORY:
        const filteredMembers = selectedLanguage === 'All' 
          ? MOCK_MEMBERS 
          : MOCK_MEMBERS.filter(m => m.languages.includes(selectedLanguage));
        return (
          <div className="max-w-6xl mx-auto">
             <div className="flex justify-between items-end mb-8 border-b border-vault-mahogany/20 pb-4">
              <div>
                <h2 className="text-3xl font-serif text-vault-mahogany">Expertise Directory</h2>
                <p className="text-stone-600 mt-1">Connect with colleagues based on operational background.</p>
              </div>
              <div className="flex items-center space-x-3">
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-white border border-stone-300 rounded-sm px-3 py-2 text-xs uppercase tracking-wider">
                   <option value="All">All Languages</option>
                   {INTERPOL_LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}
                 </select>
              </div>
             </div>
             <div className="grid md:grid-cols-2 gap-6">
               {filteredMembers.map((member: Member) => (
                 <div key={member.id} className="bg-white p-6 rounded-sm shadow-sm border border-stone-200 flex space-x-6 hover:shadow-md transition-shadow relative">
                    {member.isMentor && (
                      <div className="absolute top-0 right-0 bg-vault-amber text-vault-mahogany text-[9px] font-bold uppercase tracking-widest px-2 py-1">Available to Mentor</div>
                    )}
                    <img src={member.avatarUrl} alt={member.name} className="w-24 h-24 object-cover grayscale rounded-sm border border-stone-200" />
                    <div className="flex-1">
                      <div className="flex justify-between items-start mb-2">
                        <h3 className="text-lg font-serif text-vault-mahogany font-bold flex items-center">
                          {member.name} {member.verified && <BadgeCheck className="w-4 h-4 text-green-600 ml-2" fill="currentColor" stroke="white" />}
                        </h3>
                        <span className="text-[10px] uppercase tracking-wider border border-stone-300 px-2 py-0.5 rounded-full text-stone-500 bg-stone-50">{member.role}</span>
                      </div>
                      <p className="text-xs text-stone-500 mb-2">{member.location} • {member.years}</p>
                      <p className="text-xs italic text-stone-600 mb-4">{member.pillars.join(', ')}</p>
                      <button 
                        onClick={() => handleConnect(member.id)}
                        disabled={isConnected[member.id]}
                        className={`w-full py-2 text-xs uppercase tracking-widest transition-all flex items-center justify-center space-x-2 ${
                          isConnected[member.id] 
                          ? 'bg-stone-100 text-stone-400 border border-stone-200' 
                          : 'bg-vault-mahogany text-white hover:bg-stone-800'
                        }`}
                      >
                        {isConnected[member.id] ? <Check className="w-3 h-3" /> : null}
                        <span>{isConnected[member.id] ? 'Connected' : 'Request Connection'}</span>
                      </button>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        );

      case ViewState.VAULT_DASHBOARD:
        return (
          <div className="max-w-5xl mx-auto">
            <h1 className="text-4xl font-serif text-vault-mahogany mb-8 tracking-wide">
              {t('vault.welcome')} <span className="text-stone-400 text-xl font-light block mt-2">Dignity in service, wisdom in retirement.</span>
            </h1>
            <div className="grid md:grid-cols-4 gap-6">
               <div onClick={() => onNavigate(ViewState.VAULT_ARCHIE)} className="bg-vault-mahogany text-vault-amber p-6 rounded-sm cursor-pointer hover:bg-stone-800 transition-colors shadow-lg group">
                 <Search className="w-8 h-8 mb-4 group-hover:scale-110 transition-transform" />
                 <h3 className="text-xl font-serif mb-2">{t('vault.quick.archie')}</h3>
                 <p className="text-[10px] uppercase opacity-60">Search ground intelligence</p>
               </div>
               <div onClick={() => onNavigate(ViewState.VAULT_STORIES)} className="bg-white border border-stone-200 p-6 rounded-sm shadow-sm cursor-pointer hover:border-vault-amber transition-colors">
                 <BookOpen className="w-8 h-8 text-vault-mahogany mb-4" />
                 <h3 className="text-xl font-serif text-vault-mahogany mb-2">{t('nav.stories')}</h3>
                 <p className="text-[10px] uppercase text-stone-400">Oral history archive</p>
               </div>
               <div onClick={() => onNavigate(ViewState.VAULT_GIVING)} className="bg-vault-amber/10 border border-vault-amber/40 p-6 rounded-sm shadow-sm cursor-pointer hover:bg-vault-amber/20 transition-colors">
                 <HandHeart className="w-8 h-8 text-vault-mahogany mb-4" />
                 <h3 className="text-xl font-serif text-vault-mahogany mb-2">Giving</h3>
                 <p className="text-[10px] uppercase text-vault-mahogany/60">Support the legacy</p>
               </div>
               <div className="bg-gradient-to-br from-red-600 to-red-800 text-white p-6 rounded-sm shadow-sm">
                  <Youtube className="w-8 h-8 mb-4" />
                  <h3 className="text-xl font-serif mb-1">Featured</h3>
                  <p className="text-xs opacity-90 mb-4 line-clamp-2">Halliday's Podcast: The Future of Neutrality</p>
                  <a href="https://www.youtube.com/@HallidaysPodcast" target="_blank" rel="noopener noreferrer" className="inline-flex items-center space-x-2 text-[10px] uppercase tracking-wider bg-white/20 hover:bg-white/30 px-3 py-1.5 transition-colors font-bold"><ExternalLink className="w-3 h-3" /><span>Watch Now</span></a>
               </div>
            </div>

            <div className="mt-12 grid md:grid-cols-3 gap-8">
               <div className="md:col-span-2 space-y-6">
                  <h2 className="text-sm uppercase tracking-[0.2em] font-bold text-stone-400 flex items-center">
                    <ShieldCheck className="w-4 h-4 mr-2" /> Recent Briefings
                  </h2>
                  <div className="space-y-4">
                     {forumTopics.slice(0, 3).map(topic => (
                       <div key={topic.id} onClick={() => { setActiveTopic(topic); onNavigate(ViewState.VAULT_FORUM); }} className="bg-white p-6 border border-stone-100 hover:border-vault-amber cursor-pointer flex justify-between items-center group">
                          <div>
                             <h4 className="font-serif text-lg text-vault-mahogany group-hover:text-vault-amber transition-colors">{topic.title}</h4>
                             <p className="text-xs text-stone-500">{topic.activeCount} colleagues participating</p>
                          </div>
                          <ArrowLeft className="w-4 h-4 text-stone-200 rotate-180 group-hover:text-vault-amber transition-colors" />
                       </div>
                     ))}
                  </div>
               </div>
               <div className="space-y-6">
                  <h2 className="text-sm uppercase tracking-[0.2em] font-bold text-stone-400">Security Clearance</h2>
                  <div className="bg-vault-charcoal text-stone-300 p-6 rounded-sm border-l-4 border-vault-amber">
                     <p className="text-xs mb-4">You are currently logged in as:</p>
                     <div className="flex items-center space-x-3 mb-4">
                        <div className="w-10 h-10 bg-vault-amber rounded-sm flex items-center justify-center text-vault-mahogany font-bold">RH</div>
                        <div>
                           <p className="font-bold text-white text-sm">Ross Halliday</p>
                           <p className="text-[10px] uppercase text-stone-400">Legacy Fellow</p>
                        </div>
                     </div>
                     <div className="space-y-2">
                        <div className="flex items-center text-[10px] space-x-2 text-green-500">
                           <CheckCircle2 className="w-3 h-3" /> <span>Identity Verified</span>
                        </div>
                        <div className="flex items-center text-[10px] space-x-2 text-green-500">
                           <CheckCircle2 className="w-3 h-3" /> <span>Article 3 Compliant</span>
                        </div>
                     </div>
                  </div>
               </div>
            </div>
          </div>
        );

      case ViewState.VAULT_VERIFICATION:
      case ViewState.VAULT_FORUM:
      case ViewState.VAULT_EVENTS:
      case ViewState.VAULT_WELLBEING:
      case ViewState.VAULT_MEMBERSHIP:
      case ViewState.VAULT_ARCHIE:
        if (currentView === ViewState.VAULT_ARCHIE) return <div className="max-w-3xl mx-auto animate-fade-in-up"><div className="mb-8 text-center"><h2 className="text-3xl font-serif text-vault-mahogany mb-2">The Concierge</h2><p className="text-stone-600 italic">"I am listening. How can I facilitate your connection to the archives today?"</p></div><Archie /></div>;
        if (currentView === ViewState.VAULT_FORUM) {
           if (activeTopic) return <div className="max-w-4xl mx-auto animate-fade-in-up"><button onClick={() => {setActiveTopic(null); setAiAnalysis(null);}} className="flex items-center text-stone-500 text-xs uppercase tracking-widest mb-6 hover:text-vault-mahogany transition-colors"><ArrowLeft className="w-4 h-4 mr-1" /> Back to Briefing Room</button><div className="bg-white p-8 border-b-4 border-vault-amber shadow-sm mb-8"><div className="flex justify-between items-start mb-4"><span className="text-[10px] uppercase tracking-widest bg-stone-100 px-2 py-1 text-stone-500 rounded-sm">{activeTopic.category}</span><button onClick={handleRunAiAnalysis} disabled={isAnalyzing} className="bg-vault-amber text-vault-mahogany px-3 py-1.5 rounded-sm hover:bg-vault-amber/80 transition-all disabled:opacity-50 flex items-center space-x-2 text-xs uppercase font-bold tracking-widest shadow-sm">{isAnalyzing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}<span>Deep Analysis</span></button></div><h2 className="text-3xl font-serif text-vault-mahogany mb-4">{activeTopic.title}</h2><p className="text-stone-700 font-serif text-lg leading-relaxed mb-6">{activeTopic.description}</p>{aiAnalysis && <div className="bg-vault-charcoal text-stone-200 p-6 rounded-sm border-l-4 border-vault-amber animate-fade-in-up shadow-inner"><div className="flex items-center space-x-2 text-vault-amber mb-3"><Sparkles className="w-4 h-4" /> <span className="text-[10px] uppercase tracking-[0.2em] font-bold">Research Intelligence Output</span></div><div className="text-sm font-serif leading-relaxed whitespace-pre-wrap opacity-90">{aiAnalysis}</div></div>}</div></div>;
           return <div className="max-w-6xl mx-auto"><div className="flex justify-between items-end mb-8 border-b border-stone-200 pb-4"><div><h2 className="text-3xl font-serif text-vault-mahogany mb-2">{t('nav.briefing')}</h2><p className="text-stone-600">Private discussion channels for institutional memory.</p></div></div><div className="grid gap-4">{forumTopics.map((topic) => (<div key={topic.id} onClick={() => setActiveTopic(topic)} className="bg-white p-6 rounded-sm border-l-4 border-vault-amber shadow-sm hover:shadow-md transition-all cursor-pointer group"><div className="flex justify-between items-start mb-1"><span className="text-[9px] uppercase tracking-widest font-bold text-vault-amber bg-vault-charcoal px-2 py-0.5">{topic.category}</span><span className="text-[10px] text-stone-400">{topic.lastActive}</span></div><h3 className="text-xl font-serif text-vault-mahogany font-semibold group-hover:text-vault-amber transition-colors">{topic.title}</h3><p className="text-stone-600 mt-2 text-sm line-clamp-2">{topic.description}</p></div>))}</div></div>;
        }
        if (currentView === ViewState.VAULT_EVENTS) return <div className="max-w-6xl mx-auto"><h2 className="text-3xl font-serif text-vault-mahogany mb-8">Fellowship Calendar</h2><div className="grid md:grid-cols-3 gap-6">{events.map(event => (<div key={event.id} className="bg-white border border-stone-200 rounded-sm p-6 shadow-sm"><div className="text-[10px] uppercase text-stone-400 mb-2">{event.type}</div><h3 className="text-xl font-serif text-vault-mahogany mb-2">{event.title}</h3><div className="text-sm text-stone-500 mb-4 flex items-center"><Clock className="w-3 h-3 mr-2" />{event.date}</div><button className="w-full py-2 bg-vault-mahogany text-white text-xs uppercase tracking-widest hover:bg-stone-800 transition-colors">RSVP</button></div>))}</div></div>;
        if (currentView === ViewState.VAULT_WELLBEING) return <div className="max-w-4xl mx-auto py-12 text-center"><Heart className="w-16 h-16 text-vault-mahogany mx-auto mb-6" /><h2 className="text-4xl font-serif text-vault-mahogany mb-4">The Battle Buddy Program</h2><p className="text-lg text-stone-600 mb-8 max-w-2xl mx-auto font-serif">"Transitioning from service is a journey. We match retirees for private peer-to-peer check-ins."</p><div className="bg-white p-8 border border-stone-200 shadow-sm max-w-lg mx-auto"><button className="w-full bg-vault-mahogany text-white py-3 uppercase tracking-widest text-sm hover:bg-stone-800 transition-colors">Connect with a Buddy</button></div></div>;
        return <div className="p-8 text-center text-stone-400 uppercase tracking-widest">Consulting the Vault...</div>;
      default:
        return <div>Invalid View</div>;
    }
  };

  return (
    <div className="flex min-h-screen bg-stone-50 font-sans text-stone-800 overflow-x-hidden">
      {/* RSVP Toast */}
      {rsvpToast && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[100] bg-vault-charcoal text-vault-amber px-6 py-3 border-b-2 border-vault-amber shadow-2xl animate-fade-in-up flex items-center space-x-3">
           <ShieldCheck className="w-5 h-5" />
           <span className="text-xs uppercase font-bold tracking-widest">{rsvpToast}</span>
        </div>
      )}

      <aside className="w-64 bg-vault-charcoal flex flex-col flex-shrink-0 sticky top-0 h-screen z-[90]">
        <div className="p-6 border-b border-stone-700 text-center cursor-pointer" onClick={() => onNavigate(ViewState.VAULT_DASHBOARD)}>
          <h1 className="text-2xl font-serif text-vault-amber tracking-wider">THE VAULT</h1>
          <p className="text-slate-400 text-[10px] uppercase mt-1 tracking-widest">Institutional Custody</p>
        </div>
        <nav className="flex-1 py-8 overflow-y-auto custom-scrollbar">
           <SidebarItem view={ViewState.VAULT_DASHBOARD} icon={ShieldCheck} label={t('nav.dashboard')} />
           <SidebarItem view={ViewState.VAULT_FORUM} icon={MessageSquare} label={t('nav.briefing')} />
           <SidebarItem view={ViewState.VAULT_DIRECTORY} icon={Users} label={t('nav.directory')} />
           <SidebarItem view={ViewState.VAULT_STORIES} icon={BookOpen} label={t('nav.stories')} />
           <SidebarItem view={ViewState.VAULT_EVENTS} icon={Calendar} label={t('nav.calendar')} />
           <SidebarItem view={ViewState.VAULT_ARCHIE} icon={Search} label={t('nav.concierge')} />
           <SidebarItem view={ViewState.VAULT_WELLBEING} icon={Heart} label={t('nav.wellbeing')} />
           <SidebarItem view={ViewState.VAULT_GIVING} icon={HandHeart} label={t('nav.giving')} />
           <SidebarItem view={ViewState.VAULT_PROFILE} icon={UserCircle} label={t('nav.profile')} />
        </nav>
        <div className="p-6 border-t border-stone-700">
           <button onClick={onLogout} className="flex items-center space-x-2 text-[10px] uppercase tracking-widest text-stone-500 hover:text-white transition-colors">
             <LogOut className="w-4 h-4" /><span>Logout & Seal Vault</span>
           </button>
        </div>
      </aside>
      <main className="flex-1 overflow-y-auto">
         <div className="h-16 bg-white border-b border-stone-200 flex items-center justify-between px-8">
            <div className="relative group">
               <button className="flex items-center space-x-1 hover:text-vault-mahogany text-stone-500 text-[10px] font-bold uppercase tracking-wider">
                 <Globe className="w-4 h-4 mr-2" /><span>{language.toUpperCase()}</span>
               </button>
               <div className="absolute left-0 mt-2 w-32 bg-white text-slate-800 rounded-sm shadow-xl hidden group-hover:block border border-slate-200 z-50">
                  {(['en', 'fr', 'es', 'ar'] as LanguageCode[]).map((lang) => (
                    <button key={lang} onClick={() => setLanguage(lang)} className="block w-full text-left px-4 py-2 hover:bg-slate-100 text-xs">{lang === 'en' ? 'English' : lang === 'fr' ? 'Français' : lang === 'es' ? 'Español' : 'العربية'}</button>
                  ))}
               </div>
            </div>
            <div className="text-stone-300 text-[10px] uppercase tracking-widest">Vault Session Restricted • Article 3 Compliance Active</div>
         </div>
         <div className="p-8 md:p-12">{renderContent()}</div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes fade-in-up { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in-up { animation: fade-in-up 0.4s ease-out forwards; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #4A2C2C; }
      `}} />
    </div>
  );
};
